(function () {
	const container = document.getElementById("svgContainer");
	const svg = document.getElementById("interactiveSvg");
	const image = document.getElementById("mainImage");
	const circleImage = document.getElementById("interactiveImage");

	const paths = [
		document.getElementById("path0"),
		document.getElementById("path1")
	];

	const cursors = [
		document.getElementById("cursor0"),
		document.getElementById("cursor1")
	];

	let selectedCursor = null;
	let isDragging = false;
	let dragStartX = 0;
	let initialRatio = 0;

	const pathLengths = paths.map((p) => p.getTotalLength());
	console.log("&Toc on codepen - https://codepen.io/ol-ivier");

	function getBaseSize() {
		const width = window.innerWidth;
		if (width < 768) return { cursor: 24, image: 120 };
		if (width < 1024) return { cursor: 32, image: 180 };
		return { cursor: 48, image: 440 };
	}

	function getCursorSizes() {
		const base = getBaseSize().cursor;
		return {
			MIN_SIZE: base,
			MAX_SIZE: base * 2,
			MIN_FONT: Math.max(12, Math.round(base * 0.4)),
			MAX_FONT: Math.max(18, Math.round(base * 0.6))
		};
	}

	function updateImageSize() {
		const sizes = getBaseSize();
		circleImage.style.width = sizes.image + "px";
		circleImage.style.height = sizes.image + "px";
	}

	updateImageSize();

	const INITIAL_HUE_PERCENT = 90;
	const INITIAL_ROTATE_PERCENT = 50;

	function setCursorByRatio(index, ratio) {
		ratio = Math.min(0.5, Math.max(0, ratio));

		try {
			const pathLength = pathLengths[index];

			let pathRatio;
			if (index === 0) {
				pathRatio = ratio;
			} else {
				pathRatio = 0.5 - ratio;
			}

			const point = paths[index].getPointAtLength(pathRatio * pathLength);

			const svgPoint = svg.createSVGPoint();
			svgPoint.x = point.x;
			svgPoint.y = point.y;
			const screenPoint = svgPoint.matrixTransform(svg.getScreenCTM());

			const containerRect = container.getBoundingClientRect();
			const cursorX = screenPoint.x - containerRect.left;
			const cursorY = screenPoint.y - containerRect.top;

			cursors[index].style.left = cursorX + "px";
			cursors[index].style.top = cursorY + "px";

			const displayPercent = Math.round((ratio / 0.5) * 100);
			cursors[index].innerText = displayPercent;

			const cursorSizes = getCursorSizes();
			const progress = ratio / 0.5;
			const size =
				cursorSizes.MIN_SIZE +
				(cursorSizes.MAX_SIZE - cursorSizes.MIN_SIZE) * progress;
			const fontSize =
				cursorSizes.MIN_FONT +
				(cursorSizes.MAX_FONT - cursorSizes.MIN_FONT) * progress;

			cursors[index].style.width = size + "px";
			cursors[index].style.height = size + "px";
			cursors[index].style.fontSize = fontSize + "px";

			updateImageEffects();
		} catch (e) {}
	}

	function updateImageEffects() {
		try {
			const value0 = parseInt(cursors[0].innerText);
			const value1 = parseInt(cursors[1].innerText);

			const hueRotate = Math.round((value0 / 100) * 360);
			const rotate = Math.round((value1 / 100) * 180 - 90);

			image.style.filter = `hue-rotate(${hueRotate}deg)`;
			image.style.transform = `rotate(${rotate}deg)`;
		} catch (e) {}
	}

	function getCurrentCursorScreenX(index) {
		const left = parseFloat(cursors[index].style.left);
		if (isNaN(left)) return null;
		const containerRect = container.getBoundingClientRect();
		return left + containerRect.left + parseFloat(cursors[index].style.width) / 2;
	}

	function findClosestCursor(clientX, clientY) {
		let minDist = Infinity;
		let closestIndex = null;

		for (let i = 0; i < cursors.length; i++) {
			const left = parseFloat(cursors[i].style.left);
			const top = parseFloat(cursors[i].style.top);

			if (isNaN(left) || isNaN(top)) continue;

			const containerRect = container.getBoundingClientRect();
			const cursorScreenX =
				left + containerRect.left + parseFloat(cursors[i].style.width) / 2;
			const cursorScreenY =
				top + containerRect.top + parseFloat(cursors[i].style.height) / 2;

			const dx = clientX - cursorScreenX;
			const dy = clientY - cursorScreenY;
			const dist = Math.sqrt(dx * dx + dy * dy);

			const currentSize =
				parseFloat(cursors[i].style.width) || getCursorSizes().MAX_SIZE;
			const threshold = Math.max(40, currentSize * 1.5);

			if (dist < threshold && dist < minDist) {
				minDist = dist;
				closestIndex = i;
			}
		}
		return closestIndex;
	}

	function onDragStart(e) {
		e.preventDefault();
		let clientX = e.touches ? e.touches[0].clientX : e.clientX;
		let clientY = e.touches ? e.touches[0].clientY : e.clientY;

		const svgRect = svg.getBoundingClientRect();
		if (clientX < svgRect.left - 20 || clientX > svgRect.right + 20) return;

		const closestIndex = findClosestCursor(clientX, clientY);

		if (closestIndex !== null) {
			selectedCursor = closestIndex;
			isDragging = true;

			dragStartX = clientX;

			const currentValue = parseInt(cursors[selectedCursor].innerText) / 100;
			initialRatio = currentValue * 0.5;

			container.classList.add("dragging");

			cursors.forEach((c, i) => {
				if (i === selectedCursor) {
					c.classList.add("selected");
				} else {
					c.classList.remove("selected");
				}
			});

			window.addEventListener("mousemove", onDragMove);
			window.addEventListener("touchmove", onDragMove, { passive: false });
			window.addEventListener("mouseup", onDragEnd);
			window.addEventListener("touchend", onDragEnd);
		}
	}

	function onDragMove(e) {
		if (!isDragging || selectedCursor === null) return;
		e.preventDefault();
		let clientX = e.touches ? e.touches[0].clientX : e.clientX;

		const deltaX = clientX - dragStartX;
		const svgRect = svg.getBoundingClientRect();
		const deltaRatio = (deltaX / svgRect.width) * 0.5;

		let newRatio = initialRatio + deltaRatio;
		newRatio = Math.min(0.5, Math.max(0, newRatio));

		setCursorByRatio(selectedCursor, newRatio);
	}

	function onDragEnd() {
		if (isDragging) {
			isDragging = false;
			selectedCursor = null;
			container.classList.remove("dragging");

			cursors.forEach((c) => c.classList.remove("selected"));

			window.removeEventListener("mousemove", onDragMove);
			window.removeEventListener("touchmove", onDragMove);
			window.removeEventListener("mouseup", onDragEnd);
			window.removeEventListener("touchend", onDragEnd);
		}
	}

	container.addEventListener("mousedown", onDragStart);
	container.addEventListener("touchstart", onDragStart, { passive: false });
	svg.addEventListener("dragstart", (e) => e.preventDefault());

	window.addEventListener("resize", () => {
		updateImageSize();

		for (let i = 0; i < 2; i++) {
			const currentValue = parseInt(cursors[i].innerText) / 100;
			if (!isNaN(currentValue)) {
				setCursorByRatio(i, currentValue * 0.5);
			} else {
				setCursorByRatio(i, 0.25);
			}
		}
	});

	setTimeout(() => {
		const hueRatio = (INITIAL_HUE_PERCENT / 100) * 0.5;
		setCursorByRatio(0, hueRatio);

		const rotateRatio = (INITIAL_ROTATE_PERCENT / 100) * 0.5;
		setCursorByRatio(1, rotateRatio);
	}, 30);
})();

style.css:
* {
	box-sizing: border-box;
	user-select: none;
	margin: 0;
	padding: 0;
}

body {
	background: beige;
	min-height: 100vh;
	margin: 0;
	display: flex;
	align-items: center;
	justify-content: center;
	font-family: "Inter", system-ui, sans-serif;
	overflow: hidden;
}

.card {
	backdrop-filter: blur(12px);
	box-shadow: 0 30px 50px -15px #000000cc, inset 0 1px 2px #ffffff30;
	width: 100vw;
	height: 100vh;
	border-left: 1px solid #ff7b6b60;
	border-right: 1px solid #ff7b6b60;
	display: flex;
	flex-direction: column;
	align-items: center;
	position: relative;
	overflow: hidden;
}

.svg-container {
	position: relative;
	display: flex;
	justify-content: center;
	cursor: grab;
	touch-action: none;
	width: 80%;
	height: 100vh;
	min-height: 0;
	padding: 0;
	z-index: 10;
	margin: 0 auto;
}

.svg-container.dragging {
	cursor: grabbing;
}

svg {
	display: block;
	width: 100%;
	height: 100%;
	max-width: 100%;
	max-height: 100vh;
	filter: drop-shadow(0 10px 5px #000000b3);
	overflow: visible;
	object-fit: contain;
	pointer-events: visible;
}

.path-0 {
	stroke: #8b4513;
	stroke-width: 3;
	fill: none;
	opacity: 0.95;
	filter: drop-shadow(4px 4px 10px rgb(255 77 77 / 0.7));
}

.path-1 {
	stroke: #d35400;
	stroke-width: 3;
	fill: none;
	opacity: 0.95;
	filter: drop-shadow(4px 4px 10px rgb(255 77 77 / 0.7));
}

.html-cursor {
	position: absolute;
	border-radius: 50%;
	transform: translate(-50%, -50%);
	pointer-events: none;
	z-index: 100;
	transition: width 0.05s, height 0.05s, box-shadow 0.2s;
	display: flex;
	align-items: center;
	justify-content: center;
	font-weight: 700;
	color: #fff;
	text-shadow: 0 1px 3px #000;
	backdrop-filter: blur(2px);
	box-shadow: 0 0 0 2px rgb(255 255 255 / 0.5), 0 4px 15px rgb(0 0 0 / 0.8);
}

.cursor-0 {
	background: #8b4513;
	border: 3px solid #fff;
}

.cursor-1 {
	background: #d35400;
	border: 3px solid #fff;
	color: #1a2f3a;
	text-shadow: 0 1px 3px #fff;
}

.dragging .cursor-0,
.dragging .cursor-1 {
	box-shadow: 0 0 0 4px rgb(255 255 255 / 0.8);
}

.dragging .cursor-0 {
	background: rgb(139 69 19 / 0.95);
}

.dragging .cursor-1 {
	background: rgb(211 84 0 / 0.95);
}

.cursor-0.selected,
.cursor-1.selected {
	outline: 4px solid #fff;
	outline-offset: 4px;
}

.image-container {
	display: flex;
	justify-content: center;
	align-items: center;
	width: 100%;
	position: absolute;
	top: 50%;
	left: 0;
	transform: translateY(-50%);
	pointer-events: none;
	z-index: 20;
}

.circle-image {
	border-radius: 50%;
	border: 4px solid #fff;
	box-shadow: 0 10px 25px rgb(0 0 0 / 0.5), 0 0 0 2px rgb(255 255 255 / 0.3);
	overflow: hidden;
	transition: transform 0.3s ease, box-shadow 0.3s ease, filter 0.1s ease,
		width 0.2s, height 0.2s;
	cursor: pointer;
	pointer-events: auto;
}

.circle-image:hover {
	transform: scale(1.05);
	box-shadow: 0 15px 35px rgb(0 0 0 / 0.6), 0 0 0 3px rgb(255 255 255 / 0.5);
}

.circle-image img {
	width: 100%;
	height: 100%;
	object-fit: cover;
	display: block;
	transition: filter 0.1s ease, transform 0.1s ease;
}

.image-credit {
	text-align: left;
	color: #000;
	font-size: 0.85rem;
	opacity: 0.8;
	position: fixed;
	bottom: 20px;
	left: 10px;
	/*! width: 100%; */
	z-index: 30;
	pointer-events: none;
	width: 300px;
	padding-left: 10px;
	transform: rotate(-90deg);
	transform-origin: top left;
}

.image-credit a {
	color: #8d4b1b;
	text-decoration: none;
	pointer-events: auto;
}

.image-credit a:hover {
	text-decoration: underline;
}

.instructions-card {
	position: absolute;
	top: 20px;
	right: 20px;
	z-index: 1000;
	background: rgb(0 0 0 / 0.25);
	backdrop-filter: blur(12px);
	-webkit-backdrop-filter: blur(12px);
	border-radius: 16px;
	padding: 14px 18px;
	border: 1px solid rgb(255 255 255 / 0.2);
	box-shadow: 0 15px 30px -10px rgb(0 0 0 / 0.5);
	animation: fadeIn 0.5s ease-out;
	font-family: "Inter", system-ui, sans-serif;
}

.instructions-content {
	display: flex;
	flex-direction: column;
	gap: 10px;
	color: #fff;
}

.instruction {
	display: flex;
	align-items: center;
	gap: 10px;
	font-size: 0.95rem;
	font-weight: 500;
	text-shadow: 0 1px 3px rgb(0 0 0 / 0.5);
	white-space: nowrap;
}

.dot {
	width: 18px;
	height: 18px;
	border-radius: 50%;
	border: 2px solid #fff;
	box-shadow: 0 2px 8px rgb(0 0 0 / 0.3);
}

.dot-0 {
	background: #8d4b1b;
}

.dot-1 {
	background: #d25909;
}

.drag-hint {
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 6px;
	margin-top: 6px;
	padding-top: 8px;
	border-top: 1px solid rgb(255 255 255 / 0.2);
	font-size: 0.9rem;
	color: rgb(255 255 255 / 0.8);
}

@keyframes fadeIn {
	from {
		opacity: 0;
		transform: translateY(-10px);
	}

	to {
		opacity: 1;
		transform: translateY(0);
	}
}

@media (max-width: 768px) {
	.instructions-card {
		top: 15px;
		right: 15px;
		padding: 12px 16px;
	}

	.instruction {
		font-size: 0.85rem;
	}

	.dot {
		width: 16px;
		height: 16px;
	}
}

.copy {
	position: fixed;
	bottom: 20px;
	right: 20px;
	color: #000;
	background: rgb(255 255 255 / 0.9);
	padding: 10px;
	border-radius: 5px;
	font-size: 12px;
}
